import React, { useEffect, useState } from "react";
import { Box, Heading, Stack, Text } from "@chakra-ui/react";
import LandingPageCarousel from "../../Pages/LandingPageComponents/LandingPageCarousel";
import InProgressCarousel from "./InProgressCarousel";

const Section = ({ title, subtitle, children }) => {
  return (
    <Box mb={10}>
      <Stack spacing={2} mb={4}>
        <Heading size="lg" color="#1c1d1f">
          {title}
        </Heading>

        {subtitle && (
          <Text fontSize="sm" color="gray.600">
            {subtitle}
          </Text>
        )}
      </Stack>

      <Box bg="#f7f9fa" p={4} borderRadius="12px">
        {children}
      </Box>
    </Box>
  );
};

const CourseComponent = () => {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const url =
      "https://elearning-platform-using-mern-j5py.vercel.app/courses/all";

    fetch(url)
      .then((res) => res.json())
      .then((data) => {
        setCourses(data.course);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, []);

  return (
    <Box px={{ base: 4, md: 8 }} py={6}>
      
      <Section title="All Courses">
        <LandingPageCarousel
          courses={courses}
          loading={loading}
          category="all"
        />
      </Section>

      <Section title="In Progress Courses">
        <InProgressCarousel />
      </Section>

      <Section title="Top courses in Business">
        <LandingPageCarousel
          courses={courses}
          loading={loading}
          category="business"
        />
      </Section>

      <Section title="Top courses in IT & Software">
        <LandingPageCarousel
          courses={courses}
          loading={loading}
          category="it"
        />
      </Section>

      <Section title="Top courses in Personal Development">
        <LandingPageCarousel
          courses={courses}
          loading={loading}
          category="personal"
        />
      </Section>

    </Box>
  );
};

export default CourseComponent;
